{
  "query": "query MyPortfolio {
  platformOrganizationsCollection { edges { node { id name slug } } }
  portfolioPortfoliosCollection { edges { node { id name description } } }
}"
}

{
  "query": "query SitesHierarchy {
  portfolioPortfoliosCollection {
    edges {
      node {
        id name
        portfolioSitesCollection {
          edges {
            node {
              id name slug type addressLine1 city state sqFt
              portfolioBuildingsCollection {
                edges { node { id name floorsCount } }
              }
            }
          }
        }
      }
    }
  }
}"
}

{
  "query": "query Search($q: String!) { portfolioSearchSites(input: {q: $q}) { id name addressLine1 city } }",
  "variables": { "q": "Main" }
}

{
  "query": "query Nearby($lat: Float!, $lng: Float!) { portfolioNearbySites(input: {pLat: $lat, pLng: $lng, pRadiusMeters: 5000}) { id name distanceMeters } }",
  "variables": { "lat": 30.2672, "lng": -97.7431 }
}

{
  "query": "mutation CreateOrg($name: String!, $slug: String!) { platformCreateOrganization(input: {pName: $name, pSlug: $slug}) { id name slug } }",
  "variables": { "name": "My Property Co", "slug": "my-property-co" }
}

{
  "query": "mutation CreateSite($orgId: UUID!, $name: String!, $slug: String!, $addr: String!, $city: String!, $state: String!) { portfolioCreateSiteFull(input: {pOrgId: $orgId, pPortfolioId: null, pName: $name, pSlug: $slug, pAddressLine1: $addr, pCity: $city, pState: $state, pType: office, pFloorsCount: 5}) { id name slug } }",
  "variables": {
    "orgId": "{{orgId}}",
    "name": "200 Congress Tower",
    "slug": "200-congress-tower",
    "addr": "200 Congress Ave",
    "city": "Austin",
    "state": "TX"
  }
}

{
  "query": "query Assets($siteId: UUID!) { opsAssetsCollection(filter: {siteId: {eq: $siteId}}) { edges { node { id name status criticality qrCode manufacturer opsAssetCategories { name } portfolioSpaces { name code } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query WOs($siteId: UUID!) { opsWorkOrdersCollection(filter: {siteId: {eq: $siteId}, status: {neq: completed}}, orderBy: {priority: DescNullsLast}, first: 20) { edges { node { id title status priority slaDueAt completedAt opsAssets { name } platformProfilesByAssignedTo { fullName } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "mutation CreateWO($siteId: UUID!, $title: String!) { opsCreateWorkOrder(input: {pSiteId: $siteId, pTitle: $title, pDescription: \"Fix HVAC\", pPriority: high}) { id title status slaDueAt } }",
  "variables": { "siteId": "{{siteId}}", "title": "Fix lobby lights flickering" }
}

{
  "query": "mutation CompleteWO($id: UUID!) { opsCompleteWorkOrder(input: {pWorkOrderId: $id}) { id status completedAt } }",
  "variables": { "id": "{{workOrderId}}" }
}

{
  "query": "query Checklists { opsChecklistsCollection { edges { node { id name category estimatedMinutes opsChecklistItemsCollection { edges { node { label itemType isRequired } } } } } } }"
}

{
  "query": "mutation CreateInsp($siteId: UUID!, $checklistId: UUID!, $assetId: UUID!) { opsCreateInspectionFromChecklist(input: {pSiteId: $siteId, pChecklistId: $checklistId, pAssetId: $assetId, pTitle: \"Monthly HVAC\"}) { id title status } }",
  "variables": { "siteId": "{{siteId}}", "checklistId": "{{checklistId}}", "assetId": "{{assetId}}" }
}

{
  "query": "query Insp($siteId: UUID!) { opsInspectionsCollection(filter: {siteId: {eq: $siteId}}) { edges { node { id title status score opsInspectionItemsCollection { edges { node { status responseText isFlagged opsChecklistItems { label } } } } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "mutation CompleteInsp($id: UUID!) { opsCompleteInspection(input: {pInspectionId: $id}) { id status score } }",
  "variables": { "id": "{{inspectionId}}" }
}

{
  "query": "query LowStock($siteId: UUID!) { opsInventoryStockCollection(filter: {siteId: {eq: $siteId}}) { edges { node { quantity opsInventoryItems { name sku minStockLevel } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Ann($siteId: UUID!) { tenantAnnouncementsCollection(filter: {siteId: {eq: $siteId}, isPublished: {eq: true}}, orderBy: {publishAt: DescNullsLast}) { edges { node { id title body priority audience publishAt } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Events($siteId: UUID!) { tenantEventsCollection(filter: {siteId: {eq: $siteId}}, orderBy: {startAt: AscNullsLast}) { edges { node { id title startAt endAt locationText capacity tenantEventRsvpsCollection { edges { node { status profileId } } } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Amenities($siteId: UUID!) { tenantAmenitiesCollection(filter: {siteId: {eq: $siteId}, isBookable: {eq: true}}) { edges { node { id name category capacity hourlyRate bookingRules portfolioSpaces { name code } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Check($spaceId: UUID!, $start: Datetime!, $end: Datetime!) { tenantCheckReservationConflict(pSpaceId: $spaceId, pStart: $start, pEnd: $end) }",
  "variables": { "spaceId": "{{spaceId}}", "start": "2024-07-20T09:00:00Z", "end": "2024-07-20T10:00:00Z" }
}

{
  "query": "mutation Book($siteId: UUID!, $spaceId: UUID!, $start: Datetime!, $end: Datetime!) { tenantCreateReservation(input: {pSiteId: $siteId, pSpaceId: $spaceId, pStart: $start, pEnd: $end, pTitle: \"Team Meeting\", pAttendees: 8}) { id title startTime endTime status approvalStatus } }",
  "variables": { "siteId": "{{siteId}}", "spaceId": "{{spaceId}}", "start": "2024-07-20T09:00:00Z", "end": "2024-07-20T10:00:00Z" }
}

{
  "query": "query SR($siteId: UUID!) { tenantServiceRequestsCollection(filter: {siteId: {eq: $siteId}}, orderBy: {createdAt: DescNullsLast}) { edges { node { id title status priority tenantTenants { companyName } portfolioSpaces { name } opsWorkOrders { id status } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "mutation CreateSR($siteId: UUID!, $spaceId: UUID!, $title: String!) { tenantCreateServiceRequest(input: {pSiteId: $siteId, pSpaceId: $spaceId, pTitle: $title, pDescription: \"AC not cooling\"}) { id title status workOrderId } }",
  "variables": { "siteId": "{{siteId}}", "spaceId": "{{spaceId}}", "title": "AC not working in Suite 100" }
}

{
  "query": "query Visits($siteId: UUID!) { visitorVisitsCollection(filter: {siteId: {eq: $siteId}}, orderBy: {scheduledAt: AscNullsLast}) { edges { node { id status scheduledAt checkedInAt visitorVisitors { fullName company } platformProfilesByHostUserId { fullName } visitorPassesCollection { edges { node { qrToken status } } } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "mutation Register($siteId: UUID!, $name: String!, $email: String!) { visitorRegisterVisitor(input: {pSiteId: $siteId, pName: $name, pEmail: $email, pPurpose: \"Meeting\", pScheduledAt: \"2024-07-20T10:00:00Z\"}) { id qrCode status } }",
  "variables": { "siteId": "{{siteId}}", "name": "John Doe", "email": "john@client.com" }
}

{
  "query": "mutation GenPass($visitId: UUID!) { visitorGeneratePassForVisit(input: {pVisitId: $visitId}) { id qrToken type validFrom validUntil status } }",
  "variables": { "visitId": "{{visitId}}" }
}

{
  "query": "query Validate($token: String!) { visitorValidatePass(pToken: $token) { visitId visitorName visitorCompany status validUntil isBlacklisted hostName } }",
  "variables": { "token": "{{qrToken}}" }
}

{
  "query": "mutation CheckIn($token: String!) { visitorCheckInVisitor(input: {pToken: $token}) { id status checkedInAt } }",
  "variables": { "token": "{{qrToken}}" }
}

{
  "query": "mutation CheckOut($visitId: UUID!) { visitorCheckOutVisitor(input: {pVisitId: $visitId}) { id status checkedOutAt } }",
  "variables": { "visitId": "{{visitId}}" }
}

{
  "query": "query Stats($siteId: UUID!) { visitorGetDailyVisitorStats(pSiteId: $siteId) }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Compliance($siteId: UUID!) { vendorVendorsCollection { edges { node { id name type status vendorComplianceStatusCollection(filter: {siteId: {eq: $siteId}}) { edges { node { status issues lastChecked } } } vendorCoisCollection(orderBy: {expiryDate: AscNullsLast}) { edges { node { type expiryDate status coverageAmount } } } } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "mutation Eval($vendorId: UUID!, $siteId: UUID!) { vendorEvaluateVendorCompliance(input: {pVendorId: $vendorId, pSiteId: $siteId}) { vendorId siteId status issues lastChecked } }",
  "variables": { "vendorId": "{{vendorId}}", "siteId": "{{siteId}}" }
}

{
  "query": "query Dashboard($siteId: UUID!) { vendorVComplianceDashboardCollection(filter: {siteId: {eq: $siteId}}) { edges { node { vendorId vendorName vendorType siteName complianceStatus activeContracts validCois expiringCois expiredCois nextExpiryDate totalCoverage issues } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Rules { vendorComplianceRulesCollection { edges { node { id name vendorType requiredCoiTypes minCoverage validityDays severity isActive } } } }"
}

{
  "query": "query SiteKPIs($siteId: UUID!) { metricsGetSiteKpis(pSiteId: $siteId) }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query PortKPIs($portfolioId: UUID!) { metricsGetPortfolioKpis(pPortfolioId: $portfolioId) }",
  "variables": { "portfolioId": "{{portfolioId}}" }
}

{
  "query": "query Stats($siteId: UUID!) { metricsDailySiteStatsCollection(filter: {siteId: {eq: $siteId}}, orderBy: {date: DescNullsLast}, first: 30) { edges { node { date occupancyRate complianceRate workOrdersOpen workOrdersClosed slaBreaches visitorCount laborHours } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Bench($portfolioId: UUID!) { metricsVBuildingBenchmarkCollection(filter: {portfolioId: {eq: $portfolioId}}, orderBy: {date: DescNullsLast}) { edges { node { siteId siteName city occupancyRate complianceRate workOrdersOpen portfolioAvgOccupancy occupancyRank } } } }",
  "variables": { "portfolioId": "{{portfolioId}}" }
}

{
  "query": "query SLA($siteId: UUID!) { metricsVSlaMetricsCollection(filter: {siteId: {eq: $siteId}}, orderBy: {date: DescNullsLast}, first: 30) { edges { node { date totalWos breached overdue avgHoursToComplete urgentCount } } } }",
  "variables": { "siteId": "{{siteId}}" }
}

{
  "query": "query Reports { metricsReportsCollection { edges { node { id name type format scheduleCron status lastRunAt nextRunAt recipients metricsReportRunsCollection(first: 3, orderBy: {createdAt: DescNullsLast}) { edges { node { status filePath rowCount } } } } } } }"
}

